composition_example.code:
final class Domain extends Model implements DomainInterface
{
    use HasFactory;
    use HasUlids;
    use BelongsToApplication;    // Application boundary (host resolution)
    use BelongsToTenant;      // Tenant scope
    use HasMetadata;
    use HasUserstamps;
    use HasAuditable;
    use SoftDeletes;
}

final class DomainRecord extends Model implements DomainRecordInterface
{
    use HasFactory;
    use HasUlids;
    use BelongsToTenant;      // Tenant scope inherited via parent Domain
    use HasMetadata;
    use HasUserstamps;
    use HasAuditable;
    // NO SoftDeletes — diff-state.
}
